package com.pedrodalben.bigbangeventos.participant;
import com.pedrodalben.bigbangeventos.api.OperationResult; import com.pedrodalben.bigbangeventos.ranking.*; import com.pedrodalben.bigbangeventos.session.*; import java.time.Clock; import java.util.*;
public final class ParticipantCompletionService { private final Clock clock; public ParticipantCompletionService(Clock clock){this.clock=clock;} public synchronized OperationResult complete(EventSession s,UUID player,CompletionMode mode){if(s.state()!=SessionState.RUNNING)return OperationResult.fail("not_running","Evento não está em execução");EventParticipant p=s.participant(player).orElse(null);if(p==null)return OperationResult.fail("not_participant","Jogador não participa");if(!p.finish(clock.instant()))return OperationResult.fail("already_finished","Jogador não pode concluir novamente");Rankings.COMPLETION_ORDER.rank(s);return OperationResult.ok(mode==CompletionMode.FIRST_FINISHER?"Primeiro colocado concluiu":"Participante concluiu");} }
